+    private static func applyingSortedReplacements(
+        in text: String,
+        replacements: [CleanupReplacement]
+    ) -> String {
+        let fullRange = NSRange(text.startIndex..., in: text)
+        var occupiedRanges: [NSRange] = []
+        var scheduledReplacements: [(range: NSRange, replacement: String)] = []
+
+        for replacement in replacements {
+            guard let expression = try? NSRegularExpression(
+                pattern: phrasePattern(for: replacement.wrong),
+                options: [.caseInsensitive]
+            ) else {
+                continue
+            }
+
+            for match in expression.matches(in: text, range: fullRange) where !overlapsAnyRange(match.range, ranges: occupiedRanges) {
+                occupiedRanges.append(match.range)
+                scheduledReplacements.append((range: match.range, replacement: replacement.right))
+            }
+        }
+
+        guard !scheduledReplacements.isEmpty else {
+            return text
+        }
+
+        var result = text
+        for scheduledReplacement in scheduledReplacements.sorted(by: { $0.range.location > $1.range.location }) {
+            guard let replacementRange = Range(scheduledReplacement.range, in: result) else {
+                continue
+            }
+
+            result.replaceSubrange(replacementRange, with: scheduledReplacement.replacement)
+        }
+        return result
+    }
+
+    private static func overlapsAnyRange(_ range: NSRange, ranges: [NSRange]) -> Bool {
+        ranges.contains { NSIntersectionRange($0, range).length > 0 }
+    }
